import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

DEPT_ABBREVS = {
    'animation': ['anm', 'anim', 'ani', 'animation'],
    'compositing': ['cmp', 'comp', 'compositing'],
    'fx': ['fx', 'effects', 'vfx'],
    'effects': ['fx', 'vfx', 'effects'],
    'lighting': ['lgt', 'light', 'lit', 'lighting'],
    'layout': ['lay', 'layout'],
    'cfx': ['cfx', 'charfx', 'characterfx'],
    'character fx': ['cfx', 'charfx'],
    'modeling': ['mod', 'model', 'modeling'],
    'rigging': ['rig', 'rigging'],
    'texturing': ['tex', 'texture', 'texturing'],
    'rendering': ['rnd', 'render', 'rendering'],
    'matchmove': ['mm', 'matchmove', 'mmv'],
    'roto': ['roto', 'rot'],
    'paint': ['paint', 'pnt'],
}

class PrismGetTasksNode(BaseNode):
    name = "Prism: Get Tasks"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="")
        self.add_output("tasks", "list")
        self.add_output("count", "int")
        self.add_output("departments", "list")

    def _dept_candidates(self, dept):
        candidates = {dept}
        aliases = DEPT_ABBREVS.get(dept, [])
        candidates.update(aliases)
        for key, vals in DEPT_ABBREVS.items():
            if dept in vals:
                candidates.add(key)
                candidates.update(vals)
        return candidates

    def _tasks_from_scenefiles(self, core, entity, dept):
        files = core.entities.getScenefiles(entity) or []
        if not files:
            return [], []
        if isinstance(files[0], dict):
            self.log_info(f"scenefile sample keys: {list(files[0].keys())}")
        dept_candidates = self._dept_candidates(dept) if dept else set()
        seen_tasks = set()
        seen_depts = set()
        tasks = []
        for sf in files:
            if not isinstance(sf, dict):
                continue
            sf_dept = (sf.get("department", sf.get("step", "")) or "").lower()
            seen_depts.add(sf_dept)
            if dept and sf_dept not in dept_candidates:
                continue
            task = sf.get("task", "")
            if task and task not in seen_tasks:
                seen_tasks.add(task)
                tasks.append(task)
        return tasks, sorted(seen_depts)

    def _tasks_from_disk(self, entity, dept):
        shot_path = entity.get("path", "")
        if not shot_path:
            return [], []
        scenes_root = None
        for candidate in ("Scenefiles", "Scenes", "scenes", "scenefiles"):
            p = os.path.join(shot_path, candidate)
            if os.path.isdir(p):
                scenes_root = p
                break
        if not scenes_root:
            self.log_info(f"no Scenefiles folder in {shot_path}")
            return [], []
        all_dept_dirs = {e.name: e.path for e in os.scandir(scenes_root) if e.is_dir()}
        all_depts = sorted(all_dept_dirs.keys())
        self.log_info(f"available departments: {all_depts}")
        if not dept:
            return all_depts, all_depts
        candidates = self._dept_candidates(dept)
        dept_dir = None
        for folder, path in all_dept_dirs.items():
            if folder.lower() in candidates:
                dept_dir = path
                self.log_info(f"matched dept '{dept}' -> folder '{folder}'")
                break
        if not dept_dir:
            self.log_error(f"no folder matching '{dept}' in {scenes_root} — available: {all_depts}")
            return [], all_depts
        tasks = sorted(e.name for e in os.scandir(dept_dir) if e.is_dir())
        return tasks, all_depts

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get("entity") or {}
        dept = (inputs.get("department") or "").strip().lower()
        if core is None:
            self.log_error("No PrismCore found.")
            return {"tasks": [], "count": 0, "departments": []}
        tasks, depts = [], []
        try:
            tasks, depts = self._tasks_from_scenefiles(core, entity, dept)
        except Exception as e:
            self.log_info(f"getScenefiles error: {e}")
        if not tasks:
            tasks, depts = self._tasks_from_disk(entity, dept)
        self.log_info(f"tasks: {tasks}")
        return {"tasks": tasks, "count": len(tasks), "departments": depts}

def register_node():
    return PrismGetTasksNode
